{
}

Method.Source:
/// <summary>
/// Extension of the <c>init</c> method for the ETGSPAIN model.
/// </summary>
/// <remarks>This code is used to show or hide features in Spanish companies.</remarks>
public void init()
{
    next init();
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    /*
    this.design().controlName(formControlStr(PurchAgreementGenerateReleaseOrder, InventDim_inventBatchId)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreementGenerateReleaseOrder, InventDim_inventSerialId)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreementGenerateReleaseOrder, InventDim_InventOwnerId_RU)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreementGenerateReleaseOrder, InventDim_InventDimension1)).visible(currentCompanyIsSpanishCompany);
    */
    this.design().controlName(formControlStr(PurchAgreementGenerateReleaseOrder, ETGSPAIN_TmpPurchLine_PurchQty)).visible(currentCompanyIsSpanishCompany);        

    if (currentCompanyIsSpanishCompany == NoYes::Yes)
    {
        TmpPurchLine_DS.object(fieldNum(TmpPurchLine, PurchQty)).mandatory(true);
        InventDim_DS.object(fieldNum(InventDim, InventLocationId)).mandatory(true);
        InventDim_DS.object(fieldNum(InventDim, InventBatchId)).mandatory(true);
    }
}

/// <summary>
/// EventHandler to validate the warehouse in Spanish companies.
/// </summary>
/// <param name="sender">FormDataSource object.</param>
/// <param name="e">FormDataSourceEventArgs object.</param>
[FormDataSourceEventHandler(formDataSourceStr(PurchAgreementGenerateReleaseOrder, TmpPurchLine), FormDataSourceEventType::ValidatingWrite)]
public static void PurchCreateReleaseOrderLineTmp_OnValidatingWrite(FormDataSource sender, FormDataSourceEventArgs e)
{
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    if (currentCompanyIsSpanishCompany == NoYes::Yes)
    {
        var datasource = sender as FormDataSource;

        var args = e as FormDataSourceCancelEventArgs;

        if (args != null && datasource != null)
        {
            TmpPurchLine record = datasource.cursor() as TmpPurchLine;

            if (record.recId == 0)
            {
                InventDim inventDim = record.inventDim();

                if (!inventDim.InventLocationId)
                {
                    boolean doCancel = (Box::yesNo('@ETGSPAINLabels:PurchSalesAgreementGenerateReleaseOrderInventLocationIdWarning',DialogButton::Yes) == DialogButton::No);

                    args.cancel(doCancel);
                }                    
            }                
        }
    }
}
